def solve():
    import sys
    input = sys.stdin.read
    data = input().split()
    idx = 0
    t = int(data[idx])
    idx += 1
    for _ in range(t):
        n = int(data[idx])
        idx += 1
        a = list(map(int, data[idx:idx+n]))
        idx += n
        dp = {}
        dp[0] = 1
        dp[1] = 0
        total = 0
        for num in a:
            ndp = {}
            for mex in dp:
                cnt = dp[mex]
                if abs(num - mex) <= 1:
                    new_mex = mex if num == mex else mex + 1
                    ndp[new_mex] = (ndp.get(new_mex, 0) + cnt) % MOD
            for mex in dp:
                ndp[mex] = (ndp.get(mex, 0) + dp[mex]) % MOD
            dp = ndp
        for mex in dp:
            if mex != 0:
                total = (total + dp[mex]) % MOD
        print(total)

if __name__ == "__main__":
    solve()

